package org.apache.commons.csv;

import static org.apache.commons.csv.Token.Type.TOKEN;
import java.io.Closeable;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.Reader;
import java.io.StringReader;
import java.net.URL;
import java.nio.charset.Charset;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;
public final class CSVParser implements Iterable<CSVRecord>, Closeable{
public CSVParser(final Reader reader, final CSVFormat format) throws IOException {
        Assertions.notNull(reader, "reader");
        Assertions.notNull(format, "format");

        format.validate();
        this.format = format;
        this.lexer = new Lexer(format, new ExtendedBufferedReader(reader));
        this.headerMap = this.initializeHeader();
    }
private final CSVFormat format;
private final Map<String, Integer> headerMap;
private final Lexer lexer;
private final List<String> record = new ArrayList<String>();
private long recordNumber;
private final Token reusableToken = new Token();
public static CSVParser parse(File file, final CSVFormat format)
public static CSVParser parse(String string, final CSVFormat format)
public static CSVParser parse(URL url, Charset charset, final CSVFormat format)
private void addRecordValue()
public void close()
public long getCurrentLineNumber()
public Map<String, Integer> getHeaderMap()
public long getRecordNumber()
public List<CSVRecord> getRecords()
private Map<String, Integer> initializeHeader()
public boolean isClosed()
public Iterator<CSVRecord> iterator()
 CSVRecord nextRecord()
}
